// Created: 2026-06-07

"use client";

// Client-side Orama collections — replaces Fuse.js for the skill / agent
// browsers. One in-browser Orama DB per collection gives BM25 ranking, real
// 1-char typo tolerance, `where` faceted filtering, and native facet COUNTS
// in a single query (Fuse.js had none of these). Built once from the generated
// data already shipped to the client; no network, no SaaS.

import {
  create,
  insertMultiple,
  search,
  type AnyOrama,
} from "@orama/orama";
import { useEffect, useMemo, useState } from "react";

export interface FacetCount {
  value: string;
  count: number;
}

export interface CollectionResult<T> {
  /** Ranked items matching term + where filters. */
  items: T[];
  /** value -> count over the term-filtered set, for the facet field. */
  facets: FacetCount[];
  /** Relaxed "did you mean?" suggestions when the strict query is empty. */
  suggestions: T[];
}

interface CollectionConfig<T> {
  /** Stable id per record (used to map Orama hits back to source objects). */
  id: (item: T) => string;
  /** Orama schema for the indexed/searchable + filterable fields. */
  schema: Record<string, "string" | "string[]" | "enum" | "enum[]" | "boolean">;
  /** Project a source item into an Orama document matching `schema`. */
  toDoc: (item: T) => Record<string, unknown>;
  /** Field weights for ranking (BM25 boost). */
  boost?: Record<string, number>;
  /** Facet field to aggregate counts over (e.g. "category"). */
  facetField?: string;
}

interface QueryArgs {
  term: string;
  /** Equality / membership filters, e.g. { category: ["ai"], plugins: ["ork"] }. */
  where?: Record<string, string | string[]>;
  limit?: number;
}

/**
 * Build an Orama-backed collection. Returns a `ready` flag (Orama init is
 * async) and a synchronous-feeling `query` via React state. Use through
 * `useOramaCollection`.
 */
export function createCollection<T>(items: T[], config: CollectionConfig<T>) {
  const byId = new Map(items.map((it) => [config.id(it), it]));

  let dbPromise: Promise<AnyOrama> | null = null;
  async function getDb(): Promise<AnyOrama> {
    if (!dbPromise) {
      dbPromise = (async () => {
        const db = create({ schema: config.schema });
        await insertMultiple(
          db,
          items.map((it) => ({ id: config.id(it), ...config.toDoc(it) })),
        );
        return db;
      })();
    }
    return dbPromise;
  }

  async function query(args: QueryArgs): Promise<CollectionResult<T>> {
    const db = await getDb();
    const where = normalizeWhere(args.where);
    const res = await search(db, {
      term: args.term,
      tolerance: args.term ? 1 : 0,
      boost: config.boost,
      where: Object.keys(where).length ? where : undefined,
      facets: config.facetField ? { [config.facetField]: {} } : undefined,
      limit: args.limit ?? 500,
    });

    const items_ = res.hits
      .map((h) => byId.get(String(h.document.id)))
      .filter((x): x is T => x !== undefined);

    const facets: FacetCount[] = [];
    if (config.facetField && res.facets?.[config.facetField]) {
      const values = res.facets[config.facetField].values as Record<
        string,
        number
      >;
      for (const [value, count] of Object.entries(values))
        facets.push({ value, count });
    }

    // "Did you mean?" — looser tolerance, ignore where filters, only when the
    // strict query produced nothing.
    let suggestions: T[] = [];
    if (args.term && items_.length === 0) {
      const relaxed = await search(db, {
        term: args.term,
        tolerance: 2,
        boost: config.boost,
        limit: 3,
      });
      suggestions = relaxed.hits
        .map((h) => byId.get(String(h.document.id)))
        .filter((x): x is T => x !== undefined);
    }

    return { items: items_, facets, suggestions };
  }

  return { query };
}

function normalizeWhere(
  where: Record<string, string | string[]> | undefined,
): Record<string, unknown> {
  const out: Record<string, unknown> = {};
  if (!where) return out;
  for (const [key, val] of Object.entries(where)) {
    const arr = Array.isArray(val) ? val : [val];
    const cleaned = arr.filter(Boolean);
    if (cleaned.length) out[key] = { in: cleaned };
  }
  return out;
}

/**
 * React hook: runs `query` against an Orama collection whenever args change.
 * Returns the latest result plus a `ready` flag for the first async build.
 */
export function useOramaCollection<T>(
  collection: { query: (args: QueryArgs) => Promise<CollectionResult<T>> },
  args: QueryArgs,
): { result: CollectionResult<T>; ready: boolean } {
  const [result, setResult] = useState<CollectionResult<T>>({
    items: [],
    facets: [],
    suggestions: [],
  });
  const [ready, setReady] = useState(false);
  const key = useMemo(() => JSON.stringify(args), [args]);

  useEffect(() => {
    let active = true;
    collection.query(args).then((r) => {
      if (active) {
        setResult(r);
        setReady(true);
      }
    });
    return () => {
      active = false;
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [key, collection]);

  return { result, ready };
}
